Hi, 
The code I used is based on the ble notify example. 
I have a separate function to deal with the GPIO button interrupt response. 
It will call the writeCharacteristic and send a short command to the peripheral device. 
The peripheral device will send back an ACK notification. 
Sometimes it cause the ble to disconnect. Any idea why is that?
```
class BleNotify():
    def __init__(self):
        self.hci_port = conf["ble_hci_port"]
        self.service_uuid = conf["ble_service_uuid"]
    
    def getConn(self):
        try:
            return self.conn
        except:
            return
        
    def connect_BLE(self, MACaddr, MACtype):
        try:
            self.conn = btle.Peripheral(MACaddr, MACtype)
            try:
                self.conn.setDelegate(NotifyDelegate())
            except:
                print('fail to set the delegate')
        except:
            print('fail to connect to: %s' % MACaddr)
            try:
                self.close_BLE()
                self.conn = False
            except:
                print('BLE has already disconnected')

    def notify_Init(self):
        try:
            # Find the service
            self.svc = self.conn.getServiceByUUID(self.service_uuid)
            # Find the notification characteristics: [0] write, [1] notify
            ch_Notify = self.svc.getCharacteristics()[1]
            # Turn on the notification alert
            self.conn.writeCharacteristic(ch_Notify.valHandle+1, b'\x01\x00', withResponse=True)
        except:
            print('Service request fails')

    def notify_Write(self, text):
        # Find the notification characteristics: [0] write, [1] notify
        ch_Write = self.svc.getCharacteristics()[0]
        self.conn.writeCharacteristic(ch_Write.valHandle, text)
        print("Sent: ", text)

    def notify_Wait(self):
        return self.conn.waitForNotifications(1.0)

    def close_BLE(self):
        self.conn.disconnect()


class NotifyDelegate(btle.DefaultDelegate):
    def __init__(self):
        btle.DefaultDelegate.__init__(self)
        
    def handleNotification(self, cHandle, data):
        DBG("Data Recv:", data)
    
def main():
    try:
        b = BleNotify()
        while True:
            if b.getConn():
                try:
                    b.notify_Init()
                    while True:
                        # Wait for any notification
                        if b.notify_Wait():
                            continue
                except:
                    DBG("BLE Disconnected")
                    try:
                        b.close_BLE()
                    except:
                        pass
                    b.connect_BLE(conf["ble_mac_addr"], conf["ble_mac_type"])
                    
            else:
                b.scan_BLE(conf["ble_scan_timeout"])
                time.sleep(1)

    except KeyboardInterrupt:
        try:
            b.close_BLE()
        except:
            pass

if __name__ == '__main__':
    main()
```

This started happening after I upgraded to 0.10.0 to fix the duplicate Model name issue I reported earlier. We discovered that we started getting errors such as 

`Type of value given to save() method is not a valid SQLALchemy declarative class. Item with index 0 and with value "`

Upon further debugging by looking at the instance of SQLClient via .models.values() we discovered an empty dictionary. I saw in the 0.10.0 change log that there was some kind of code change for this. I'm not sure if it's related to how we instantiate the base class but I've posted a bit of our code to help out.

database.py
```
from sqlservice import SQLClient
from orm import Model
from config import BaseConfig

config = {
    'SQL_DATABASE_URI': 'postgresql://{0}:{1}@{2}:{3}/{4}'.format(
        BaseConfig.DATABASE['DB_USER'], BaseConfig.DATABASE['DB_PASS'],
        BaseConfig.DATABASE['DB_SERVICE'], BaseConfig.DATABASE['DB_PORT'],
        BaseConfig.DATABASE['DB_NAME'])
}

db = SQLClient(config, model_class=Model)
```

orm.Model
```
import datetime

import sqlalchemy as sa

from sqlservice import declarative_base, ModelBase

from sqlalchemy import MetaData
from sqlalchemy.ext.declarative import declared_attr


meta = MetaData(naming_convention={
    "ix": 'ix_%(column_0_label)s',
    "uq": "uk_%(table_name)s_%(column_0_name)s",
    "ck": "ck_%(constraint_name)s",
    "fk": "fk_%(column_0_name)s_%(referred_table_name)s",
    "pk": "pk_%(table_name)s"
}, schema='public')

class MyCustomBase(ModelBase):
    @declared_attr
    def created_by(cls):
        return sa.Column(sa.SmallInteger, sa.ForeignKey('public.user.user_id'))

    @declared_attr
    def created_ts(cls):
        return sa.Column(sa.DateTime(timezone=False), nullable=False,
                         default=datetime.datetime.utcnow,
                         server_default=sa.func.now())

    @declared_attr
    def modified_by(cls):
        return sa.Column(sa.SmallInteger, sa.ForeignKey('public.user.user_id'))

    @declared_attr
    def modified_ts(cls):
        return sa.Column(sa.DateTime(timezone=False),
                         onupdate=datetime.datetime.utcnow,
                         server_onupdate=sa.func.now())


Model = declarative_base(MyCustomBase, metadata=meta)
```

Subsequent model files then import Model from orm.Model like so
```
import sqlalchemy as sa
from sqlalchemy.dialects.postgresql.json import JSON

from orm import Model

class User(Model):
    __tablename__ = 'user'

    user_id = sa.Column(sa.Integer, primary_key=True)
```

